// ── Item 1 — group by (query, session/agent, time-window), not by producer ──
// dev-request 2026-07-04-rfb-samtaler-ekte-samtalevisning, item 1.
console.log("── conversation-ui group-by-query tests ──");

// Build one producer conversation belonging to a search fan-out. Each producer
// gets its own thread; the fan-out shares taskId/source/queryText/time.
function fanoutConv(o: {
  id: string; query: string; sellerId: string; sellerName: string;
  reply?: string; taskId?: string; buyerAgentId?: string; source?: string;
  clientIdentity?: string; at?: string;
}): any {
  const at = o.at || "2026-07-09T14:23:01.000Z";
  const messages: any[] = [
    { senderRole: "system", content: `Søk: "${o.query}"`, metadata: { queryText: o.query, ...(o.clientIdentity ? { clientIdentity: o.clientIdentity } : {}) } },
  ];
  if (o.reply !== undefined) {
    messages.push({ senderRole: "seller", content: o.reply, metadata: { autoGenerated: true } });
  }
  return {
    id: o.id, queryText: o.query, source: o.source || "a2a",
    taskId: o.taskId, buyerAgentId: o.buyerAgentId, sellerAgentId: o.sellerId,
    sellerAgentName: o.sellerName, createdAt: at, updatedAt: at, messages,
  };
}

// (a) N one-shot conversations for the SAME query+session collapse to ONE card
// with a "N produsenter svarte" header (N = distinct producers).
{
  const fanout = [
    fanoutConv({ id: "c1", query: "honning bergen", sellerId: "s1", sellerName: "Birøkter A", reply: "Hei fra Birøkter A! 👋", taskId: "task-XYZ" }),
    fanoutConv({ id: "c2", query: "honning bergen", sellerId: "s2", sellerName: "Birøkter B", reply: "Hei fra Birøkter B! 👋", taskId: "task-XYZ" }),
    fanoutConv({ id: "c3", query: "honning bergen", sellerId: "s3", sellerName: "Birøkter C", reply: "Hei fra Birøkter C! 👋", taskId: "task-XYZ" }),
    fanoutConv({ id: "c4", query: "honning bergen", sellerId: "s4", sellerName: "Birøkter D", reply: "Hei fra Birøkter D! 👋", taskId: "task-XYZ" }),
    fanoutConv({ id: "c5", query: "honning bergen", sellerId: "s5", sellerName: "Birøkter E", reply: "Hei fra Birøkter E! 👋", taskId: "task-XYZ" }),
    fanoutConv({ id: "c6", query: "honning bergen", sellerId: "s6", sellerName: "Birøkter F", reply: "Hei fra Birøkter F! 👋", taskId: "task-XYZ" }),
  ];
  const groups = groupConversationsForList(fanout);
  assertEq(groups.length, 1, "group: 6-producer fan-out for one query+session → ONE card");
  assertEq(groups[0]!.conversations.length, 6, "group: all 6 distinct producers kept inside the card");
  assertEq(groups[0]!.queryText, "honning bergen", "group: card carries the query text");
  // The rendered header is `${count} produsenter svarte`; prove the count is 6.
  assertEq(`${groups[0]!.conversations.length} produsenter svarte`, "6 produsenter svarte",
    "group: header renders «honning bergen» → 6 produsenter svarte");
}

// (b) Different queries stay in separate cards.
{
  const groups = groupConversationsForList([
    fanoutConv({ id: "a1", query: "honning bergen", sellerId: "s1", sellerName: "A", reply: "r", taskId: "t1" }),
    fanoutConv({ id: "b1", query: "epler oslo", sellerId: "s2", sellerName: "B", reply: "r", taskId: "t2" }),
  ]);
  assertEq(groups.length, 2, "group: two different queries → two cards");
}

// (c) SAME query, DIFFERENT session (different A2A task) stay separate — this is
// the whole point of item 1's key and is exactly what the pre-slice-2
// query-only grouping got wrong (it would have merged these into one card).
{
  const groups = groupConversationsForList([
    fanoutConv({ id: "s1a", query: "honning bergen", sellerId: "p1", sellerName: "A", reply: "r1", taskId: "task-1" }),
    fanoutConv({ id: "s2a", query: "honning bergen", sellerId: "p1", sellerName: "A", reply: "r1", taskId: "task-2" }),
  ]);
  assertEq(groups.length, 2, "group: same query, different session (taskId) → two cards");
}

// (d) SAME query+session but DIFFERENT time-window (hours apart) stay separate.
{
  const groups = groupConversationsForList([
    fanoutConv({ id: "t1", query: "ost trondheim", sellerId: "p1", sellerName: "A", reply: "r", source: "mcp", clientIdentity: "ChatGPT", at: "2026-07-09T09:00:00.000Z" }),
    fanoutConv({ id: "t2", query: "ost trondheim", sellerId: "p2", sellerName: "B", reply: "r", source: "mcp", clientIdentity: "ChatGPT", at: "2026-07-09T15:00:00.000Z" }),
  ]);
  assertEq(groups.length, 2, "group: same query+client, different hour bucket → two cards");
}

// (e) Kill the 3× repetition: the SAME producer answering the SAME query with an
// identical reply, captured three times, collapses to ONE sub-card. On the
// pre-slice-2 (no-dedup) code this group would hold 3 identical entries.
{
  const dupReply = "Hei fra Kjells Gård! 👋 Spesialiteter: honning";
  const groups = groupConversationsForList([
    fanoutConv({ id: "d1", query: "honning", sellerId: "kjell", sellerName: "Kjells Gård", reply: dupReply, taskId: "tk" }),
    fanoutConv({ id: "d2", query: "honning", sellerId: "kjell", sellerName: "Kjells Gård", reply: dupReply, taskId: "tk" }),
    fanoutConv({ id: "d3", query: "honning", sellerId: "kjell", sellerName: "Kjells Gård", reply: dupReply, taskId: "tk" }),
  ]);
  assertEq(groups.length, 1, "dedupe: repeated fan-out of one query → one card");
  assertEq(groups[0]!.conversations.length, 1, "dedupe: 3× identical producer+reply → ONE sub-card");
  // No two snippets in the group are identical (acceptance: no adjacent dup text).
  const snips = groups[0]!.snippets;
  const uniqueSnips = new Set(snips);
  assertEq(uniqueSnips.size, snips.length, "dedupe: no two sub-cards share identical reply text");
}

// (f) Distinct producers with genuinely different replies are NOT over-deduped.
{
  const groups = groupConversationsForList([
    fanoutConv({ id: "u1", query: "egg", sellerId: "p1", sellerName: "Gård A", reply: "Hei fra Gård A! egg 30kr", taskId: "te" }),
    fanoutConv({ id: "u2", query: "egg", sellerId: "p2", sellerName: "Gård B", reply: "Hei fra Gård B! egg 35kr", taskId: "te" }),
  ]);
  assertEq(groups[0]!.conversations.length, 2, "dedupe: different producers/replies both kept");
}

// conversationSessionKey: strongest stable key first, honest empty fallback.
assertEq(conversationSessionKey({ id: "x", taskId: "T", buyerAgentId: "B", messages: [] }), "task:T",
  "sessionKey: taskId wins");
assertEq(conversationSessionKey({ id: "x", buyerAgentId: "B", messages: [] }), "buyer:B",
  "sessionKey: buyerAgentId when no task");
assertEq(conversationSessionKey({ id: "x", messages: [{ senderRole: "system", metadata: { clientIdentity: "ChatGPT" } }] }), "client:ChatGPT",
  "sessionKey: clientIdentity from opening system message");
assertEq(conversationSessionKey({ id: "x", messages: [{ senderRole: "system", metadata: {} }] }), "",
  "sessionKey: honest empty when nothing identifies the searcher (never fabricated)");

// conversationGroupKey: no query text → never merges distinct conversations.
{
  const a = conversationGroupKey({ id: "a", messages: [] });
  const b = conversationGroupKey({ id: "b", messages: [] });
  assertTrue(a !== b, "groupKey: empty-query conversations never collapse together");
}

// sellerReplySnippet: last seller reply, truncated; empty when no reply.
assertEq(sellerReplySnippet({ id: "x", messages: [{ senderRole: "system", content: "s" }] }), "",
  "snippet: no seller reply → empty");
assertEq(sellerReplySnippet({ id: "x", messages: [{ senderRole: "seller", content: "hei" }] }), "hei",
  "snippet: short reply passes through");
assertTrue(sellerReplySnippet({ id: "x", messages: [{ senderRole: "seller", content: "a".repeat(200) }] }).endsWith("..."),
  "snippet: long reply truncated with ellipsis");

// ── Item 5 — chat-transcript view (/samtale/:id) as a real chat ─────────────
// dev-request 2026-07-04-rfb-samtaler-ekte-samtalevisning, item 5.
console.log("── conversation-ui chat-transcript (item 5) tests ──");

// A full auto-reply exactly as generateSellerResponse builds it: greeting +
// product answer + specialties, then the STATIC boilerplate block (hours +
// contact + delivery + payment + cert + profile link) + closing.
const ITEM5_REPLY = [
  "Hei fra Kjells Gård! 👋",
  "Vi har det du leter etter:",
  "• Honning — 89 kr",
  "",
  "Spesialiteter: honning, voks",
  "",
  "🕐 Åpningstider: Man 9–17, Lør 10–15",
  "",
  "Kontakt oss:",
  "📍 Bygdevegen 3, 5000",
  "📞 90012345",
  "✉️ post@kjell.no",
  "🌐 kjell.no",
  "🚚 Levering: hjemlevering (inntil 20 km)",
  "💳 Betaling: Vipps, kort",
  "✅ Debio-godkjent",
  "",
  "🔗 Se profilen vår: https://rettfrabonden.com/produsent/kjells-gaard",
  "",
  "Ta gjerne kontakt for spørsmål eller bestilling!",
].join("\n");

// splitSellerReply: boilerplate pulled OUT of the body, conversational content kept.
{
  const { body, card } = splitSellerReply(ITEM5_REPLY);
  assertTrue(card !== null, "splitSellerReply: contact card extracted from a full auto-reply");
  assertEq(card!.hours, "Man 9–17, Lør 10–15", "splitSellerReply: opening hours captured (label stripped)");
  // Conversational content STAYS in the bubble body.
  assertTrue(body.includes("Hei fra Kjells Gård"), "splitSellerReply: greeting stays in body");
  assertTrue(body.includes("• Honning"), "splitSellerReply: product line stays in body");
  assertTrue(body.includes("Spesialiteter"), "splitSellerReply: specialties stay in body");
  assertTrue(body.includes("Ta gjerne kontakt"), "splitSellerReply: closing stays in body");
  // Boilerplate GONE from the bubble body.
  assertTrue(!body.includes("Åpningstider"), "splitSellerReply: hours removed from bubble body");
  assertTrue(!body.includes("📞"), "splitSellerReply: phone line removed from bubble body");
  assertTrue(!body.includes("📍"), "splitSellerReply: address line removed from bubble body");
  assertTrue(!body.includes("Betaling"), "splitSellerReply: payment line removed from bubble body");
  assertTrue(!body.includes("Se profilen"), "splitSellerReply: profile link removed from bubble body");
  // Card carries the contact lines.
  assertTrue(card!.lines.some(l => l.includes("📞")), "splitSellerReply: phone lands in card");
  assertTrue(card!.lines.some(l => l.includes("🔗 Se profilen")), "splitSellerReply: profile link lands in card");
}

// splitSellerReply: a plain reply with no boilerplate → no card, body untouched.
{
  const { body, card } = splitSellerReply("Hei fra Gård A! 👋 egg 30 kr");
  assertEq(card, null, "splitSellerReply: no boilerplate → no card");
  assertEq(body, "Hei fra Gård A! 👋 egg 30 kr", "splitSellerReply: plain reply body untouched");
}

// renderTranscriptBody: question bubble (real query text) BEFORE the producer
// reply; boilerplate contact/hours renders exactly ONCE (card), not per-bubble;
// query echo suppressed; auto-reply tag preserved; no "Forhandling".
{
  const conv = {
    buyerAgentName: "Kjøper-agent",
    sellerAgentName: "Kjells Gård",
    queryText: "honning fra bergen",
    source: "a2a",
    createdAt: "2026-07-09T14:23:01.000Z",
    messages: [
      { senderRole: "system", content: `Søk: "honning fra bergen" → Match: Kjells Gård (Bergen).`,
        messageType: "info", metadata: { queryText: "honning fra bergen" }, createdAt: "2026-07-09T14:23:01.000Z" },
      { senderRole: "seller", senderAgentName: "Kjells Gård", content: ITEM5_REPLY,
        messageType: "offer", metadata: { autoGenerated: true }, createdAt: "2026-07-09T14:23:02.000Z" },
    ],
  };
  const html = renderTranscriptBody(conv);
  const qIdx = html.indexOf("honning fra bergen");
  const replyIdx = html.indexOf("Hei fra Kjells Gård");
  assertTrue(qIdx >= 0, "transcript: question text rendered");
  assertTrue(replyIdx >= 0, "transcript: producer reply rendered");
  assertTrue(qIdx < replyIdx, "transcript: question bubble comes BEFORE the producer reply (timeline)");
  // Query renders exactly once — the echo system message is suppressed.
  assertEq(html.split("honning fra bergen").length - 1, 1,
    "transcript: query text renders exactly ONCE (echo system message suppressed)");
  // Contact/hours boilerplate renders exactly ONCE (the card), not in the bubble.
  assertEq(html.split("90012345").length - 1, 1, "transcript: phone/contact renders exactly ONCE");
  assertEq(html.split("Åpningstider").length - 1, 1, "transcript: opening-hours renders exactly ONCE");
  assertTrue(html.includes("contact-card"), "transcript: compact contact card rendered");
  // Boilerplate is absent from the reply bubble content itself (it's in the card).
  const bubbleSlice = html.slice(replyIdx);
  const cardIdx = html.indexOf("contact-card");
  assertTrue(cardIdx > replyIdx, "transcript: card renders AFTER (below) the producer reply bubble");
  assertTrue(bubbleSlice.slice(0, cardIdx - replyIdx).indexOf("Se profilen") === -1,
    "transcript: profile-link boilerplate NOT inside the reply bubble");
  // Slice-1 honesty preserved.
  assertTrue(html.includes("automatisk svar fra profilen"), "transcript: auto-reply tag preserved on producer bubble");
  assertTrue(!html.includes("Forhandling"), "transcript: no fabricated 'Forhandling' label");
}

// renderTranscriptBody: no stored query text → no fabricated question bubble;
// falls back to rendering the real system message honestly.
{
  const html = renderTranscriptBody({
    sellerAgentName: "Gård B",
    createdAt: "2026-07-09T10:00:00.000Z",
    messages: [
      { senderRole: "system", content: "Ny samtale startet med Gård B.", messageType: "info", metadata: {}, createdAt: "2026-07-09T10:00:00.000Z" },
    ],
  });
  assertTrue(!html.includes("msg-question"), "transcript: no question bubble fabricated when queryText is absent");
  assertTrue(html.includes("Ny samtale startet"), "transcript: real system message still rendered when no query");
}

console.log("── pii-redact tests ──");

// ── SHOULD REDACT ──────────────────────────────────────────────────────
assertEq(redactPII("skf@hjortegarden.no"), "[skjult e-post]", "email: bare address");
assertEq(redactPII("Kontakt oss: post@farm.com om du har spørsmål"),
  "Kontakt oss: [skjult e-post] om du har spørsmål", "email: in sentence");
assertEq(redactPII("test.me+tag@sub.example.co.uk"), "[skjult e-post]", "email: plus-tag + subdomain + 2nd-level TLD");
assertEq(redactPII("+47 41 63 22 99"), "[skjult tlf]", "phone: +47 with spaces");
assertEq(redactPII("+4741632299"), "[skjult tlf]", "phone: +47 no spaces");
assertEq(redactPII("Ring 41632299 i dag"), "Ring [skjult tlf] i dag", "phone: plain 8-digit starting with 4");
assertEq(redactPII("90012345"), "[skjult tlf]", "phone: plain 8-digit starting with 9");

const validFnr = makeValidFnr("010190125"); // 01-01-1990, male, low individual number
assertTrue(isValidFodselsnummer(validFnr), `isValidFodselsnummer(${validFnr})`);
assertEq(redactPII(`Fødselsnummer ${validFnr}`), "Fødselsnummer [skjult]", "fnr: valid checksum redacted");
assertEq(redactPII(`Fnr: ${validFnr.slice(0, 6)} ${validFnr.slice(6)}`),
  "Fnr: [skjult]", "fnr: 6+5 split with space also matched");

// ── SHOULD NOT REDACT (false-positive guards) ─────────────────────────
assertEq(redactPII("Hjortegården"), "Hjortegården", "producer name");
assertEq(redactPII("oslo"), "oslo", "city name");
assertEq(redactPII("organic honey near Bergen"), "organic honey near Bergen", "English query");
assertEq(redactPII("ost og kjøtt"), "ost og kjøtt", "category terms");
assertEq(redactPII("gamkinn"), "gamkinn", "obscure search term");
assertEq(redactPII("Brønnøysund org 923456789"), "Brønnøysund org 923456789", "9-digit org number");
assertEq(redactPII("Postnr 3577"), "Postnr 3577", "4-digit postal code");
assertEq(redactPII("kr 150,-"), "kr 150,-", "price format");
assertEq(redactPII("10:00-17:00"), "10:00-17:00", "opening hours");
assertEq(redactPII("https://rettfrabonden.com/teknologi"),
  "https://rettfrabonden.com/teknologi", "URL with path");
assertEq(redactPII("60.494, 8.513"), "60.494, 8.513", "coordinates");
assertEq(redactPII("12345678"), "12345678", "8-digit starting with 1 — not Norwegian phone range");
assertEq(redactPII("Product-456-789"), "Product-456-789", "SKU / product code");
assertEq(redactPII("12345678901"), "12345678901", "11-digit without valid checksum (not a fnr)");
assertEq(redactPII("98765432109"), "98765432109", "another random 11-digit — random checksum miss");
assertEq(redactPII("Ordrenummer 109295152"), "Ordrenummer 109295152", "9-digit order number");
assertEq(redactPII("Se 2026-04-23 for dato"), "Se 2026-04-23 for dato", "ISO date");

// ── EDGE CASES ────────────────────────────────────────────────────────
assertEq(redactPII(""), "", "empty string returns empty");
assertEq(redactPII(null), "", "null returns empty string");
assertEq(redactPII(undefined), "", "undefined returns empty string");
assertEq(
  redactPII("Send til post@farm.no og ring +47 40404040"),
  "Send til [skjult e-post] og ring [skjult tlf]",
  "multiple PII in one string",
);
assertEq(
  redactPII("hjortegården stokke"),
  "hjortegården stokke",
  "actual search term from query logs",
);
assertEq(
  redactPII("skf@hjortegarden.no"),
  "[skjult e-post]",
  "actual PII search term from query logs (the one that triggered this work)",
);

