// ─── content-refresh-attempt-tracking: failed attempts don't block forever ──
// Regression guard for `controller-handoff/2026-07-05-experiences-enrichment-
// content-refresh-aggregator-1.md`: selectProvidersForContentRefresh() used to
// order candidates by last_enriched_at, which is stamped ONLY on a successful
// write. A provider whose homepage is permanently unreachable (dead site /
// wrong aggregator URL) never succeeds, so it never gets a timestamp and sorts
// first FOREVER — starving every other eligible candidate once the pool
// exceeds the per-run cap. Fix: a separate last_content_attempt_at column,
// stamped via markProviderContentAttempted() on every attempt regardless of
// outcome, now drives the ordering instead.
console.log("\n── content-refresh-attempt-tracking: failed attempts cycle to the back ──");
(() => {
  const prevPathCRA = process.env.EXPERIENCES_DB_PATH;
  process.env.EXPERIENCES_DB_PATH = ":memory:";

  const dbFacPathCRA = require.resolve("../src/database/db-factory");
  const expStPathCRA = require.resolve("../src/services/experience-store");
  delete require.cache[dbFacPathCRA];
  delete require.cache[expStPathCRA];

  const dbFacCRA = require("../src/database/db-factory") as typeof import("../src/database/db-factory");
  dbFacCRA.__resetDbFactoryForTesting();
  const expStCRA = require("../src/services/experience-store") as typeof import("../src/services/experience-store");

  dbFacCRA.getDb("experiences");

  // Two eligible providers, both with a website and a thin (no description/
  // category) experience. Provider A is created first, so absent any attempt
  // tracking it would always sort first (created_at ASC tiebreak).
  const provA = expStCRA.createProvider({
    navn: "Stuck Aggregator AS", org_nr: "900111222",
    fylke: "Troms", kommune: "Tromsø",
    hjemmeside: "https://dmo-aggregator.example/stuck-aggregator",
    brreg_verified: 1, brreg_active: 1, verification_status: "verified",
  });
  expStCRA.createExperience({
    title: "Stuck Aggregator opplevelse", provider_id: provA, provider_match_status: "matched",
    fylke: "Troms", kommune: "Tromsø", confidence: "high", verification_status: "pending_verify",
  });
  const provB = expStCRA.createProvider({
    navn: "Fresh Provider AS", org_nr: "900333444",
    fylke: "Troms", kommune: "Tromsø",
    hjemmeside: "https://fresh-provider.example",
    brreg_verified: 1, brreg_active: 1, verification_status: "verified",
  });
  expStCRA.createExperience({
    title: "Fresh Provider opplevelse", provider_id: provB, provider_match_status: "matched",
    fylke: "Troms", kommune: "Tromsø", confidence: "high", verification_status: "pending_verify",
  });

  // cra-01: before any attempt, both providers have last_content_attempt_at
  // NULL — tiebreak falls to created_at ASC, so the first-created (provA)
  // wins a cap=1 selection. This is pre-existing, expected behavior.
  const firstPick = expStCRA.selectProvidersForContentRefresh(1);
  assertEq(firstPick.length, 1, "cra-01a: selectProvidersForContentRefresh(1) returns exactly 1");
  assertEq(firstPick[0]?.id, provA, "cra-01b: with no attempts yet, oldest-created (provA) sorts first");

  // cra-02: stamp provA as attempted (simulating a content-refresh pass whose
  // fetch failed — this is exactly what processOne() now does unconditionally
  // in apply mode, before it even tries the fetch).
  const stamped = expStCRA.markProviderContentAttempted(provA);
  assertTrue(stamped, "cra-02: markProviderContentAttempted returns true (row changed)");

  // cra-03: provA must now have a real timestamp, not NULL.
  const dbCRA = dbFacCRA.getDb("experiences");
  const rowA = dbCRA.prepare("SELECT last_content_attempt_at FROM experience_providers WHERE id = ?").get(provA) as { last_content_attempt_at: string | null };
  assertTrue(!!rowA.last_content_attempt_at, "cra-03: provA.last_content_attempt_at is set after an attempt");

  // cra-04: THE FIX — a cap=1 selection now prefers provB (never attempted,
  // NULL sorts first) over provA (attempted, has a real timestamp). Before
  // this fix, provA (permanently unreachable in production) would have kept
  // winning this slot on every single call, forever.
  const secondPick = expStCRA.selectProvidersForContentRefresh(1);
  assertEq(secondPick.length, 1, "cra-04a: second selectProvidersForContentRefresh(1) returns exactly 1");
  assertEq(secondPick[0]?.id, provB, "cra-04b: after provA's attempt is stamped, never-attempted provB sorts first");

  if (prevPathCRA === undefined) delete process.env.EXPERIENCES_DB_PATH;
  else process.env.EXPERIENCES_DB_PATH = prevPathCRA;
  dbFacCRA.__resetDbFactoryForTesting();
  console.log("  content-refresh-attempt-tracking: OK (6 tests: initial-order/stamp-returns-true/timestamp-set/reorder-after-attempt)");
})();

// ─── gardssalg-book: reservation → confirmation journey (2026-07-02) ────────
// Regression coverage for the live "Book besøk" 404: gårdssalg producers
// (experience_providers rows with producer_type set / rfb-seed) have ZERO
// rows in `experiences`, so /tilbyder/<slug> — which requires ≥1 published
// experience — always 404'd for them. getGardssalgProviderBySlug() + the new
// /kategori/gardssalg/book/* routes fix that without touching /tilbyder or
// any other vertical. Covers: reservation panel render, unknown-slug 404, the
// no-JS POST fallback creating a real booking + redirecting, invalid-input
// handling, and the /kategori/gardssalg card CTA fix (now points at the
// booking route, gated on slug not hjemmeside). Same isolated :memory:
// experiences DB + sync mock req/res pattern as the p2/sq-caticon blocks
// above — fully synchronous, so it cannot race the async report tail.
console.log("\n── gardssalg-book: reservation → confirmation journey ──");
(() => {
  const prevPathGB = process.env.EXPERIENCES_DB_PATH;
  process.env.EXPERIENCES_DB_PATH = ":memory:";
  // dev-request 2026-07-12-gardssalg-dark-launch-stop, slice 0: booking
  // submission now hard-stops unless BOOKING_DISPATCH_ENABLED=true AND the
  // specific provider is booking_live=1 (see isBookingPaused() in
  // services/booking-store.ts). This block's whole point is regression
  // coverage for the "already onboarded" reservation → confirmation journey,
  // so it opts the seeded provider IN to the live state below (mirrors the
  // acceptance criteria: "simulate via a direct DB update in a test"). The
  // dark-launch-stop gate itself (flag off / provider not live) gets its own
  // dedicated test block further down.
  const prevDispatchGB = process.env.BOOKING_DISPATCH_ENABLED;
  process.env.BOOKING_DISPATCH_ENABLED = "true";

  const dbFacPathGB = require.resolve("../src/database/db-factory");
  const expStPathGB = require.resolve("../src/services/experience-store");
  const bookStPathGB = require.resolve("../src/services/booking-store");
  const expSeoPathGB = require.resolve("../src/routes/experiences-seo");
  delete require.cache[dbFacPathGB];
  delete require.cache[expStPathGB];
  delete require.cache[bookStPathGB];
  delete require.cache[expSeoPathGB];

  const dbFacGB = require("../src/database/db-factory") as typeof import("../src/database/db-factory");
  dbFacGB.__resetDbFactoryForTesting();
  const expStGB = require("../src/services/experience-store") as typeof import("../src/services/experience-store");
  const bookStGB = require("../src/services/booking-store") as typeof import("../src/services/booking-store");
  const seoRouterGB = (require("../src/routes/experiences-seo") as typeof import("../src/routes/experiences-seo")).default as any;

  const dbGB = dbFacGB.getDb("experiences");

  // Seed a gårdssalg producer: producer_type set, deliberately NO hjemmeside
  // and NO experiences rows at all — exactly the shape that always 404'd via
  // /tilbyder/<slug> before this fix, and (separately) never got a "Book
  // besøk" button at all under the old hjemmeside-gated CTA. NOTE: the
  // gårdssalg classification column is `producer_type` (bryggeri/sideri/...),
  // a DIFFERENT column from the general `provider_type` that createProvider()/
  // ProviderSchema sets — there's no service-layer setter for it (it's
  // populated by the enrichment pipeline in production), so the test sets it
  // directly via SQL, same as that pipeline would.
  const provIdGB = expStGB.createProvider({
    navn: "Fjellro Sideri", org_nr: "912345678",
    fylke: "Innlandet", kommune: "Lillehammer", poststed: "Lillehammer",
    brreg_verified: 0, verification_status: "pending_verify",
  });
  dbGB.prepare("UPDATE experience_providers SET producer_type = ? WHERE id = ?").run("sideri", provIdGB);
  // booking_live=1 — this producer is treated as already onboarded for the
  // purposes of this regression block (see comment above).
  dbGB.prepare("UPDATE experience_providers SET booking_live = 1 WHERE id = ?").run(provIdGB);
  expStGB.backfillProviderSlugs();

  // invokeSeo — same shape as the p2/sq-caticon helpers, generalized to pick
  // GET or POST (Express gives each method its own Route/layer even when the
  // path string is identical, so filtering by path+method is unambiguous).
  function invokeGB(
    method: "get" | "post",
    routePath: string,
    params: Record<string, string>,
    reqPath: string,
    opts: { query?: Record<string, string>; body?: Record<string, unknown> } = {}
  ): { status: number; body: string; headers: Record<string, string>; redirectTo: string | null } {
    const layer = (seoRouterGB.stack as any[]).find(
      (l: any) => l.route && l.route.path === routePath && l.route.methods?.[method]
    );
    assertTrue(!!layer, `gb-route: router has ${method.toUpperCase()} ${routePath} layer`);
    if (!layer) return { status: 0, body: "", headers: {}, redirectTo: null };
    let status = 200; let body = ""; let nexted = false; let redirectTo: string | null = null;
    const headers: Record<string, string> = {};
    const res: any = {
      statusCode: 200,
      setHeader: (k: string, v: string) => { headers[k.toLowerCase()] = String(v); },
      status: (c: number) => { status = c; res.statusCode = c; return res; },
      send: (b: unknown) => { body = typeof b === "string" ? b : String(b); return res; },
      json: (o: unknown) => { body = JSON.stringify(o); return res; },
      redirect: (code: number, location: string) => { status = code; redirectTo = location; },
    };
    // req.body pre-populated directly (as express.urlencoded() would leave
    // it) — we invoke only the route's final handler, same as invokeSeo does,
    // skipping the urlencoded() middleware layer itself (no real req stream
    // to parse in this mock).
    const req: any = { path: reqPath, hostname: "opplevagent.no", params, query: opts.query || {}, body: opts.body || {} };
    const stack = (layer.route.stack as any[]).filter((s: any) => s.method === method);
    const handle = stack[stack.length - 1].handle;
    handle(req, res, () => { nexted = true; });
    if (nexted) status = 404;
    return { status, body, headers, redirectTo };
  }

  // gb-01: unknown slug → 404 (next()) — this is the exact live bug: before
  // the fix, ANY gårdssalg slug hit this same 404 path via /tilbyder/<slug>.
  const missGB = invokeGB("get", "/kategori/gardssalg/book/:providerSlug",
    { providerSlug: "finnes-ikke" }, "/kategori/gardssalg/book/finnes-ikke");
  assertEq(missGB.status, 404, "gb-01: unknown provider slug → 404 (next())");

  const seededGB = expStGB.listGardssalgProviders(10, 0).find((p: any) => p.id === provIdGB);
  assertTrue(!!seededGB && !!seededGB.slug, "gb-02: seeded provider got a slug from backfillProviderSlugs()");
  const slugGB = String(seededGB!.slug);

  // gb-03: reservation panel renders for the seeded producer (this used to be
  // an unconditional 404 for every gårdssalg provider).
  const panelGB = invokeGB("get", "/kategori/gardssalg/book/:providerSlug",
    { providerSlug: slugGB }, `/kategori/gardssalg/book/${slugGB}`);
  assertEq(panelGB.status, 200, "gb-03a: GET /kategori/gardssalg/book/<slug> → 200 (was a 404 before this fix)");
  assertTrue(/text\/html/.test(panelGB.headers["content-type"] || ""), "gb-03b: panel Content-Type text/html");
  assertTrue(panelGB.body.includes("Fjellro Sideri"), "gb-03c: panel shows provider name");
  assertTrue(panelGB.body.includes("Sider"), "gb-03d: panel shows the drink-type badge (sideri → Sider)");
  assertTrue(panelGB.body.includes("Du betaler ingenting nå"), "gb-03e: panel shows the no-payment microcopy");
  assertTrue(panelGB.body.includes(`value="${provIdGB}"`), "gb-03f: hidden provider_id field carries the real provider id");
  assertTrue(new RegExp(`method="POST" action="[^"]*${slugGB}"`).test(panelGB.body),
    "gb-03g: form POSTs to a URL that works without JS (true HTML form target)");
  assertTrue(panelGB.body.includes('type="datetime-local"'), "gb-03h: slot_at is a datetime-local input");
  assertTrue(panelGB.body.includes('name="guest_phone"'), "gb-03i: guest_phone field is present");
  assertTrue(!panelGB.body.includes('id="guest_phone" name="guest_phone" type="tel" maxlength="30" required'),
    "gb-03j: guest_phone is optional (no required attribute)");
  assertTrue(!/kjøp alkohol|selg alkohol|betal for alkohol/i.test(panelGB.body),
    "gb-03k: no alcohol-purchase language on the reservation panel");

  // gb-04: POST no-JS fallback with invalid input → redirect back with ?error=invalid.
  const badPostGB = invokeGB("post", "/kategori/gardssalg/book/:providerSlug",
    { providerSlug: slugGB }, `/kategori/gardssalg/book/${slugGB}`,
    { body: { slot_at: "", party_size: "2", guest_name: "Ola", guest_email: "not-an-email" } });
  assertEq(badPostGB.status, 303, "gb-04a: invalid no-JS submission → 303 redirect");
  assertTrue((badPostGB.redirectTo || "").includes("error=invalid"), "gb-04b: redirect carries ?error=invalid");

  // gb-05/06: POST no-JS fallback with valid input → creates a REAL booking
  // row via createBooking() and redirects straight to the confirmation URL.
  // Both this fallback and the JSON API (POST /api/opplevelser/book) call the
  // exact same createBooking()/sendBookingConfirmation() from booking-store.ts
  // — nothing is duplicated between the two entry points.
  const goodPostGB = invokeGB("post", "/kategori/gardssalg/book/:providerSlug",
    { providerSlug: slugGB }, `/kategori/gardssalg/book/${slugGB}`,
    {
      body: {
        slot_at: "2026-08-15T14:00", party_size: "3",
        guest_name: "Kari Nordmann", guest_email: "kari@example.no", guest_phone: "12345678",
      },
    });
  assertEq(goodPostGB.status, 303, "gb-05a: valid no-JS submission → 303 redirect");
  const redirGB = goodPostGB.redirectTo || "";
  assertTrue(redirGB.startsWith(`/kategori/gardssalg/book/${slugGB}/confirm/`),
    "gb-05b: redirects to the confirm sub-path for the same provider slug");
  const refGB = decodeURIComponent(redirGB.split("/confirm/")[1] || "");
  assertTrue(/^GARD-\d{8}-[A-Z0-9]{5}$/.test(refGB), "gb-05c: booking_ref has the GARD-YYYYMMDD-XXXXX shape");

  const bookingGB = bookStGB.getBookingByRef(refGB);
  assertTrue(!!bookingGB, "gb-06a: booking exists via getBookingByRef() (same lookup function /ics uses)");
  assertEq(bookingGB?.provider_id, provIdGB, "gb-06b: booking is attached to the correct provider");
  assertEq(bookingGB?.party_size, 3, "gb-06c: party_size persisted correctly");
  assertEq(bookingGB?.guest_name, "Kari Nordmann", "gb-06d: guest_name persisted correctly");
  assertEq(bookingGB?.status, "reserved", "gb-06e: new booking starts in 'reserved' status");

  // gb-07: a second gårdssalg producer with NO hjemmeside — under the OLD CTA
  // gate ("has a hjemmeside") this row would get no button at all; under the
  // fixed slug-based gate it does, and the /kategori/gardssalg listing links
  // both providers at the new booking route (not the dead /tilbyder/<slug>).
  const otherProvIdGB = expStGB.createProvider({
    navn: "Annet Bryggeri",
    fylke: "Innlandet", kommune: "Lillehammer",
  });
  dbGB.prepare("UPDATE experience_providers SET producer_type = ? WHERE id = ?").run("bryggeri", otherProvIdGB);
  expStGB.backfillProviderSlugs();
  const otherRowGB = expStGB.listGardssalgProviders(20, 0).find((p: any) => p.id === otherProvIdGB);
  assertTrue(!!otherRowGB && !!otherRowGB.slug, "gb-07a: second seeded provider (no hjemmeside) also got a slug");

  const listGB = invokeGB("get", "/kategori/gardssalg", {}, "/kategori/gardssalg");
  assertEq(listGB.status, 200, "gb-08a: GET /kategori/gardssalg → 200");
  assertTrue(listGB.body.includes(`/kategori/gardssalg/book/${slugGB}`),
    "gb-08b: listing links the seeded provider to the new booking route");
  assertTrue(!listGB.body.includes(`/tilbyder/${slugGB}`),
    "gb-08c: listing no longer links this provider to the dead /tilbyder/<slug> route");
  assertTrue(listGB.body.includes("Book besøk"), "gb-08d: 'Book besøk' CTA text still present");
  assertTrue(!!otherRowGB && listGB.body.includes(`/kategori/gardssalg/book/${otherRowGB.slug}`),
    "gb-08e: CTA gate is now slug-based, not hjemmeside-based (shows for a producer with no website)");

  if (prevPathGB === undefined) delete process.env.EXPERIENCES_DB_PATH;
  else process.env.EXPERIENCES_DB_PATH = prevPathGB;
  if (prevDispatchGB === undefined) delete process.env.BOOKING_DISPATCH_ENABLED;
  else process.env.BOOKING_DISPATCH_ENABLED = prevDispatchGB;
  dbFacGB.__resetDbFactoryForTesting();
  console.log("  gardssalg-book: OK (panel render, unknown-slug 404, no-JS POST create+redirect, provider ownership, CTA fix)");
})();

// ─── gardssalg-dark-launch-stop: BOOKING_DISPATCH_ENABLED / booking_live gate
//     (dev-request 2026-07-12-gardssalg-dark-launch-stop, slice 0) ──────────
// The gårdssalg booking flow has looked fully functional on prod since
// 2026-07-03 (real form, "confirmation" screen, confirmation email) but no
// producer is ever notified and no producer has been onboarded — Daniel
// ordered an immediate dark-launch stop. Covers: the fail-safe default of
// bookingDispatchEnabled()/isBookingPaused() (anything but the literal
// string "true" means paused), the three SSR "coming soon" notices (booking
// panel, produsent-profile reserve CTA, category-card discreet badge), the
// hard stop on BOTH booking-submission entry points (POST
// /api/opplevelser/book JSON API + the no-JS SSR fallback) — no reserved
// row, no guest email, no producer notification while paused — the
// ?error=paused banner reusing the existing error-banner path, and the
// flag-on + booking_live=1 happy path: the pre-existing chain works exactly
// as before (reserved row, guest email, confirm-token redirect) PLUS a
// producer notification is now attempted, including the "no epost on file"
// safety case. Same isolated :memory: experiences DB + sync mock req/res
// pattern as the gardssalg-book block above — every path exercised here
// resolves its response before its first internal `await` (fire-and-forget
// email sends), so calling handlers without awaiting is safe and this stays
// fully synchronous, unable to race the async report tail.
console.log("\n── gardssalg-dark-launch-stop: BOOKING_DISPATCH_ENABLED / booking_live gate ──");
(() => {
  const prevPathGDL = process.env.EXPERIENCES_DB_PATH;
  process.env.EXPERIENCES_DB_PATH = ":memory:";
  const prevDispatchGDL = process.env.BOOKING_DISPATCH_ENABLED;

  const dbFacPathGDL = require.resolve("../src/database/db-factory");
  const expStPathGDL = require.resolve("../src/services/experience-store");
  const bookStPathGDL = require.resolve("../src/services/booking-store");
  const expSeoPathGDL = require.resolve("../src/routes/experiences-seo");
  const opplevelserPathGDL = require.resolve("../src/routes/opplevelser");
  delete require.cache[dbFacPathGDL];
  delete require.cache[expStPathGDL];
  delete require.cache[bookStPathGDL];
  delete require.cache[expSeoPathGDL];
  delete require.cache[opplevelserPathGDL];

  const dbFacGDL = require("../src/database/db-factory") as typeof import("../src/database/db-factory");
  dbFacGDL.__resetDbFactoryForTesting();
  const expStGDL = require("../src/services/experience-store") as typeof import("../src/services/experience-store");
  const bookStGDL = require("../src/services/booking-store") as typeof import("../src/services/booking-store");
  const seoRouterGDL = (require("../src/routes/experiences-seo") as typeof import("../src/routes/experiences-seo")).default as any;
  const oppRouterGDL = (require("../src/routes/opplevelser") as typeof import("../src/routes/opplevelser")).default as any;

  const dbGDL = dbFacGDL.getDb("experiences");

  // Capture-pattern (same as the "EMAIL SERVICE" block earlier in this file):
  // override the shared emailService singleton's sendEmail so we can assert
  // on whether/how many emails were attempted, without any real SMTP calls.
  // The push happens synchronously the instant sendEmail() is called (before
  // its first internal await), so it's already recorded by the time the
  // fire-and-forget .catch()-chained call sites here return.
  const emailSvcModGDL = require("../src/services/email-service") as typeof import("../src/services/email-service");
  const origSendGDL = emailSvcModGDL.emailService.sendEmail.bind(emailSvcModGDL.emailService);
  let emailCallsGDL: Array<{ to: string; subject: string }> = [];
  (emailSvcModGDL.emailService as any).sendEmail = async (opts: { to: string; subject: string }) => {
    emailCallsGDL.push({ to: opts.to, subject: opts.subject });
    return { success: true, messageId: "test" };
  };

  // ── gdl-00: bookingDispatchEnabled()/isBookingPaused() fail-safe unit coverage
  delete process.env.BOOKING_DISPATCH_ENABLED;
  assertEq(bookStGDL.bookingDispatchEnabled(), false, "gdl-00a: bookingDispatchEnabled() defaults false when the env var is unset");
  process.env.BOOKING_DISPATCH_ENABLED = "false";
  assertEq(bookStGDL.bookingDispatchEnabled(), false, "gdl-00b: bookingDispatchEnabled() false for the literal string \"false\"");
  process.env.BOOKING_DISPATCH_ENABLED = "1";
  assertEq(bookStGDL.bookingDispatchEnabled(), false, "gdl-00c: bookingDispatchEnabled() false for any non-\"true\" value (fail-safe)");
  process.env.BOOKING_DISPATCH_ENABLED = "true";
  assertEq(bookStGDL.bookingDispatchEnabled(), true, "gdl-00d: bookingDispatchEnabled() true only for the literal string \"true\"");
  assertEq(bookStGDL.isBookingPaused(1), false, "gdl-00e: isBookingPaused(1) is false when dispatch is enabled and the provider is live");
  assertEq(bookStGDL.isBookingPaused(0), true, "gdl-00f: isBookingPaused(0) is true even with dispatch enabled (provider not live)");
  assertEq(bookStGDL.isBookingPaused(null), true, "gdl-00g: isBookingPaused(null) is true (fail-safe when booking_live is unknown)");
  delete process.env.BOOKING_DISPATCH_ENABLED;
  assertEq(bookStGDL.isBookingPaused(1), true, "gdl-00h: isBookingPaused(1) is still true when dispatch is off globally, live provider or not");

  // Seed a gårdssalg producer — booking_live defaults to 0 (additive column,
  // never flipped to 1 by this slice), with a real epost on file so the
  // producer-dispatch path (once live) has somewhere to send to.
  const provIdGDL = expStGDL.createProvider({
    navn: "Nordlys Bryggeri", org_nr: "923456789",
    fylke: "Troms", kommune: "Tromsø", poststed: "Tromsø",
    brreg_verified: 0, verification_status: "pending_verify",
  });
  dbGDL.prepare("UPDATE experience_providers SET producer_type = ?, epost = ? WHERE id = ?")
    .run("bryggeri", "post@nordlysbryggeri.no", provIdGDL);
  expStGDL.backfillProviderSlugs();
  const seededGDL = expStGDL.listGardssalgProviders(10, 0).find((p: any) => p.id === provIdGDL);
  assertTrue(!!seededGDL && !!seededGDL.slug, "gdl-01: seeded provider got a slug");
  const slugGDL = String(seededGDL!.slug);
  assertEq(seededGDL!.booking_live, 0, "gdl-02: booking_live defaults to 0 on a freshly-migrated row (additive column)");

  // invokeSeoGDL — same shape as the gardssalg-book block's invokeGB helper.
  function invokeSeoGDL(
    method: "get" | "post",
    routePath: string,
    params: Record<string, string>,
    reqPath: string,
    opts: { query?: Record<string, string>; body?: Record<string, unknown> } = {}
  ): { status: number; body: string; headers: Record<string, string>; redirectTo: string | null } {
    const layer = (seoRouterGDL.stack as any[]).find(
      (l: any) => l.route && l.route.path === routePath && l.route.methods?.[method]
    );
    assertTrue(!!layer, `gdl-route: seo router has ${method.toUpperCase()} ${routePath} layer`);
    if (!layer) return { status: 0, body: "", headers: {}, redirectTo: null };
    let status = 200; let body = ""; let nexted = false; let redirectTo: string | null = null;
    const headers: Record<string, string> = {};
    const res: any = {
      statusCode: 200,
      setHeader: (k: string, v: string) => { headers[k.toLowerCase()] = String(v); },
      status: (c: number) => { status = c; res.statusCode = c; return res; },
      send: (b: unknown) => { body = typeof b === "string" ? b : String(b); return res; },
      json: (o: unknown) => { body = JSON.stringify(o); return res; },
      redirect: (code: number, location: string) => { status = code; redirectTo = location; },
    };
    const req: any = { path: reqPath, hostname: "opplevagent.no", params, query: opts.query || {}, body: opts.body || {} };
    const stack = (layer.route.stack as any[]).filter((s: any) => s.method === method);
    const handle = stack[stack.length - 1].handle;
    handle(req, res, () => { nexted = true; });
    if (nexted) status = 404;
    return { status, body, headers, redirectTo };
  }

  // invokeOppGDL — invokes the JSON API's POST /book handler directly (same
  // "grab the last handler in the route's stack, call with a mock req/res"
  // idiom as invokeSeoGDL / the pre-existing opplevelser router tests
  // elsewhere in this file, e.g. the orch19 POST /a2a dispatcher block).
  function invokeOppGDL(body: Record<string, unknown>): { status: number; json: any } {
    const layer = (oppRouterGDL.stack as any[]).find(
      (l: any) => l.route && l.route.path === "/book" && l.route.methods?.post
    );
    assertTrue(!!layer, "gdl-route: opplevelser router has POST /book layer");
    let status = 200; let jsonBody: any = null;
    const res: any = {
      status: (c: number) => { status = c; return res; },
      json: (o: unknown) => { jsonBody = o; return res; },
    };
    const req: any = { body };
    const handle = layer.route.stack[layer.route.stack.length - 1].handle;
    handle(req, res, () => {});
    return { status, json: jsonBody };
  }

  function countBookingsGDL(): number {
    return (dbGDL.prepare("SELECT COUNT(*) AS c FROM gardssalg_bookings").get() as { c: number }).c;
  }

  // ═══ Paused (real-world default state today: flag off, provider not live) ═══
  delete process.env.BOOKING_DISPATCH_ENABLED;

  // gdl-03: booking panel — persistent "coming soon" notice, no claim that
  // booking works today, and the <form> itself still renders (submission is
  // what's actually blocked — see gdl-06 — not the form's visibility).
  const panelGDL = invokeSeoGDL("get", "/kategori/gardssalg/book/:providerSlug",
    { providerSlug: slugGDL }, `/kategori/gardssalg/book/${slugGDL}`);
  // NOTE: assertions below key off the `notice-paused` CSS class, not a raw
  // substring match on "ikke aktive ennå"/"kommer snart" — the panel's inline
  // <script> ALSO embeds "Reservasjoner er ikke aktive ennå — kommer snart."
  // as its client-side fallback message (shown if a submit races a flag
  // flip), so that phrase is present in the page source in BOTH the
  // live and paused states. The server-rendered notice block is the only
  // paused-specific signal.
  assertEq(panelGDL.status, 200, "gdl-03a: GET booking panel still 200 when paused");
  assertTrue(panelGDL.body.includes('class="notice-paused"'), "gdl-03b: panel shows the server-rendered 'not active yet' notice block");
  assertTrue(panelGDL.body.includes("ikke aktive ennå"), "gdl-03c: panel notice text includes 'ikke aktive ennå'");
  assertTrue(!panelGDL.body.includes("Du betaler ingenting nå — dette er en reservasjon."),
    "gdl-03d: panel does NOT show the 'this is a reservation' microcopy that would imply it works today");
  assertTrue(panelGDL.body.includes('method="POST"'), "gdl-03e: the reservation <form> itself is still present (only submission is blocked)");

  // gdl-04: produsent profile — same signal on the reserve CTA; CTA
  // href/button text unchanged (no-regression guarantee for the existing
  // gardssalg-profile block's gp-05/gp-05b assertions).
  const profileGDL = invokeSeoGDL("get", "/kategori/gardssalg/produsent/:providerSlug",
    { providerSlug: slugGDL }, `/kategori/gardssalg/produsent/${slugGDL}`);
  assertEq(profileGDL.status, 200, "gdl-04a: GET produsent profile still 200 when paused");
  assertTrue(profileGDL.body.includes('class="reserve-notice"'), "gdl-04b: profile reserve CTA shows the 'not active yet' notice");
  assertTrue(profileGDL.body.includes(`href="/kategori/gardssalg/book/${slugGDL}"`),
    "gdl-04c: profile CTA href is unchanged");
  assertTrue(profileGDL.body.includes("Reserver besøk"), "gdl-04d: profile CTA button text is unchanged");

  // gdl-05: category browse page — discreet "kommer snart" badge on the card.
  const listGDL = invokeSeoGDL("get", "/kategori/gardssalg", {}, "/kategori/gardssalg");
  assertEq(listGDL.status, 200, "gdl-05a: GET category page still 200");
  assertTrue(listGDL.body.includes("Kommer snart"), "gdl-05b: category card shows the discreet 'Kommer snart' badge");

  // gdl-06: POST no-JS fallback while paused → 303 redirect back to the
  // panel with ?error=paused, NO booking row created, NO emails attempted.
  const beforeCountGDL = countBookingsGDL();
  emailCallsGDL = [];
  const postPausedGDL = invokeSeoGDL("post", "/kategori/gardssalg/book/:providerSlug",
    { providerSlug: slugGDL }, `/kategori/gardssalg/book/${slugGDL}`,
    { body: { slot_at: "2026-08-20T14:00", party_size: "2", guest_name: "Per Hansen", guest_email: "per@example.no" } });
  assertEq(postPausedGDL.status, 303, "gdl-06a: no-JS POST while paused → 303 redirect");
  assertTrue((postPausedGDL.redirectTo || "").endsWith("?error=paused"), "gdl-06b: redirect carries ?error=paused");
  assertEq(countBookingsGDL(), beforeCountGDL, "gdl-06c: no reserved row created while paused");
  assertEq(emailCallsGDL.length, 0, "gdl-06d: no email (guest or producer) attempted while paused");

  // gdl-07: the panel renders the ?error=paused banner via the existing
  // bookingErrorMessage()/errorBanner path (a new switch case, not a
  // duplicated banner).
  const errBannerGDL = invokeSeoGDL("get", "/kategori/gardssalg/book/:providerSlug",
    { providerSlug: slugGDL }, `/kategori/gardssalg/book/${slugGDL}`, { query: { error: "paused" } });
  assertTrue(errBannerGDL.body.includes('role="alert"'), "gdl-07a: ?error=paused renders the role=alert error banner");
  assertTrue(errBannerGDL.body.includes("ikke aktive ennå"), "gdl-07b: ?error=paused banner shows the same honest copy");

  // gdl-08: POST /api/opplevelser/book (JSON API) while paused → explicit
  // paused/coming-soon JSON (200, so the panel's fetch() script doesn't treat
  // it as a network error), no reserved row, no emails.
  const beforeCountGDL2 = countBookingsGDL();
  emailCallsGDL = [];
  const jsonPausedGDL = invokeOppGDL({
    provider_id: provIdGDL, slot_at: "2026-08-21T12:00", party_size: 2,
    guest_name: "Kari Olsen", guest_email: "kari.olsen@example.no",
  });
  assertEq(jsonPausedGDL.status, 200, "gdl-08a: POST /api/opplevelser/book while paused → 200 (not a network-error status)");
  assertEq(jsonPausedGDL.json?.success, false, "gdl-08b: success:false while paused");
  assertEq(jsonPausedGDL.json?.paused, true, "gdl-08c: paused:true in the JSON response");
  assertTrue(typeof jsonPausedGDL.json?.message === "string" && jsonPausedGDL.json.message.length > 0,
    "gdl-08d: a human-readable 'coming soon' message is included");
  assertEq(countBookingsGDL(), beforeCountGDL2, "gdl-08e: no reserved row created via the JSON API while paused");
  assertEq(emailCallsGDL.length, 0, "gdl-08f: no email attempted via the JSON API while paused");

  // ═══ Live (flag on AND this specific provider booking_live=1) — the full
  // pre-existing chain must work exactly as before, PLUS a producer
  // notification. ═══
  process.env.BOOKING_DISPATCH_ENABLED = "true";
  dbGDL.prepare("UPDATE experience_providers SET booking_live = 1 WHERE id = ?").run(provIdGDL);

  // gdl-09: booking panel notice gone, original microcopy restored.
  const panelLiveGDL = invokeSeoGDL("get", "/kategori/gardssalg/book/:providerSlug",
    { providerSlug: slugGDL }, `/kategori/gardssalg/book/${slugGDL}`);
  assertTrue(!panelLiveGDL.body.includes('class="notice-paused"'), "gdl-09a: panel notice gone once flag=on and provider is booking_live");
  assertTrue(panelLiveGDL.body.includes("Du betaler ingenting nå — dette er en reservasjon."),
    "gdl-09b: original no-payment microcopy restored once live");

  // gdl-10: produsent profile CTA notice gone; category badge gone.
  const profileLiveGDL = invokeSeoGDL("get", "/kategori/gardssalg/produsent/:providerSlug",
    { providerSlug: slugGDL }, `/kategori/gardssalg/produsent/${slugGDL}`);
  assertTrue(!profileLiveGDL.body.includes('class="reserve-notice"'), "gdl-10a: profile CTA notice gone once live");
  const listLiveGDL = invokeSeoGDL("get", "/kategori/gardssalg", {}, "/kategori/gardssalg");
  assertTrue(!listLiveGDL.body.includes("Kommer snart"), "gdl-10b: category badge gone once live");

  // gdl-11: no-JS POST fallback while live → real booking created, guest +
  // producer emails BOTH attempted (existing chain unaffected — same
  // createBooking()/sendBookingConfirmation() as before, ICS/QR/
  // confirm-token flow all untouched, PLUS the new producer dispatch).
  emailCallsGDL = [];
  const postLiveGDL = invokeSeoGDL("post", "/kategori/gardssalg/book/:providerSlug",
    { providerSlug: slugGDL }, `/kategori/gardssalg/book/${slugGDL}`,
    { body: { slot_at: "2026-08-22T15:00", party_size: "4", guest_name: "Lise Berg", guest_email: "lise@example.no" } });
  assertEq(postLiveGDL.status, 303, "gdl-11a: valid no-JS submission while live → 303 redirect (unchanged)");
  const redirLiveGDL = postLiveGDL.redirectTo || "";
  assertTrue(redirLiveGDL.includes("/confirm/"), "gdl-11b: redirects to the confirm sub-path (unchanged)");
  const refLiveGDL = decodeURIComponent(redirLiveGDL.split("/confirm/")[1] || "");
  const bookingLiveGDL = bookStGDL.getBookingByRef(refLiveGDL);
  assertTrue(!!bookingLiveGDL, "gdl-11c: reserved row created via getBookingByRef() (unchanged)");
  assertEq(bookingLiveGDL?.status, "reserved", "gdl-11d: booking starts 'reserved' (unchanged)");
  assertEq(emailCallsGDL.length, 2, "gdl-11e: both the guest confirmation AND the producer notification were attempted");
  assertTrue(emailCallsGDL.some((c) => c.to === "lise@example.no"), "gdl-11f: guest confirmation addressed to the guest");
  assertTrue(emailCallsGDL.some((c) => c.to === "post@nordlysbryggeri.no"), "gdl-11g: producer notification addressed to the provider's epost");

  // gdl-12: JSON API while live → 201 created, real booking, both emails.
  emailCallsGDL = [];
  const jsonLiveGDL = invokeOppGDL({
    provider_id: provIdGDL, slot_at: "2026-08-23T10:00", party_size: 1,
    guest_name: "Jon Dahl", guest_email: "jon@example.no",
  });
  assertEq(jsonLiveGDL.status, 201, "gdl-12a: POST /api/opplevelser/book while live → 201 (unchanged)");
  assertEq(jsonLiveGDL.json?.success, true, "gdl-12b: success:true while live");
  assertTrue(!!jsonLiveGDL.json?.booking_ref, "gdl-12c: booking_ref present (unchanged)");
  assertEq(emailCallsGDL.length, 2, "gdl-12d: both guest and producer emails attempted via the JSON API too");

  // gdl-13: a second, live provider with NO epost on file — the producer
  // dispatch must never throw or block the guest's booking; only the
  // producer send is skipped (a console warning is logged, not asserted
  // here — just the non-throw + guest-still-sent behavior).
  const provNoEmailGDL = expStGDL.createProvider({
    navn: "Fjordsmak Sideri", org_nr: "934567890",
    fylke: "Troms", kommune: "Tromsø",
  });
  dbGDL.prepare("UPDATE experience_providers SET producer_type = ?, booking_live = 1 WHERE id = ?")
    .run("sideri", provNoEmailGDL);
  emailCallsGDL = [];
  const jsonNoEpostGDL = invokeOppGDL({
    provider_id: provNoEmailGDL, slot_at: "2026-08-24T11:00", party_size: 2,
    guest_name: "Silje Vik", guest_email: "silje@example.no",
  });
  assertEq(jsonNoEpostGDL.status, 201, "gdl-13a: booking still succeeds when the provider has no epost on file");
  assertEq(emailCallsGDL.length, 1, "gdl-13b: only the guest confirmation is attempted (producer send skipped, not thrown)");
  assertTrue(emailCallsGDL.some((c) => c.to === "silje@example.no"), "gdl-13c: guest still gets their confirmation");

  (emailSvcModGDL.emailService as any).sendEmail = origSendGDL;
  if (prevPathGDL === undefined) delete process.env.EXPERIENCES_DB_PATH;
  else process.env.EXPERIENCES_DB_PATH = prevPathGDL;
  if (prevDispatchGDL === undefined) delete process.env.BOOKING_DISPATCH_ENABLED;
  else process.env.BOOKING_DISPATCH_ENABLED = prevDispatchGDL;
  dbFacGDL.__resetDbFactoryForTesting();
  console.log("  gardssalg-dark-launch-stop: OK (fail-safe flag default, SSR notices x3, hard stop on both entry points incl. no-row/no-email guarantees, flag-on+booking_live full-chain regression, producer dispatch + missing-epost safety)");
})();

// gb-qr: qrcode SVG generation smoke test. Isolated — touches no DB/Express
// state at all — so it's safe to run through the async serial chain without
// racing the fully-synchronous block above (which completes end-to-end
// before any microtask, including this one, gets a chance to run).
const _gardssalgQrPromise = runSerial(async () => {
  const QRCodeGB = require("qrcode");
  const svg: string = await QRCodeGB.toString("GARD-20260815-ABCDE", { type: "svg", margin: 1, width: 180 });
  assertTrue(typeof svg === "string" && svg.includes("<svg"), "gb-qr-01: QRCode.toString(type:'svg') returns inline SVG markup");
  // Generated locally by the `qrcode` library (no HTTP call to any third-party
  // QR image service); the only "http" text present is the standard SVG XML
  // namespace declaration, not a network reference.
  assertTrue(!/<image[^>]+(https?:)?\/\//.test(svg) && !svg.includes("api.qrserver") && !svg.includes("googleapis.com/chart"),
    "gb-qr-02: generated SVG embeds no <image> reference to a third-party QR service (booking_ref never leaves our infra)");
});

// ─── gardssalg-profile: produsent profile page (2026-07-03, Fase 1 of the
//     rike-profiler dev-request) ────────────────────────────────────────────
// Regression coverage for GET /kategori/gardssalg/produsent/:providerSlug —
// the new "sell/decide" page between the /kategori/gardssalg listing and the
// /kategori/gardssalg/book/<slug> reservation panel. Resolves via the exact
// same getGardssalgProviderBySlug() gate as the booking panel (see the
// gardssalg-book block above), so covers: unknown-slug 404, a fully-seeded
// slug rendering all sections (hero/badge, "Om produsenten", "Besøket",
// practical info table, map block, reserve CTA), LocalBusiness +
// BreadcrumbList JSON-LD, OG/Twitter tags, the /kategori/gardssalg
// category-card name-link now pointing at the profile route (not straight at
// booking), and a no-regression check that the booking panel itself still
// renders. Same isolated :memory: experiences DB + sync mock req/res pattern
// as the gardssalg-book/sq-caticon blocks — fully synchronous, so it cannot
// race the async report tail.
console.log("\n── gardssalg-profile: produsent profile page ──");
(() => {
  const prevPathGP = process.env.EXPERIENCES_DB_PATH;
  process.env.EXPERIENCES_DB_PATH = ":memory:";

  const dbFacPathGP = require.resolve("../src/database/db-factory");
  const expStPathGP = require.resolve("../src/services/experience-store");
  const expSeoPathGP = require.resolve("../src/routes/experiences-seo");
  delete require.cache[dbFacPathGP];
  delete require.cache[expStPathGP];
  delete require.cache[expSeoPathGP];

  const dbFacGP = require("../src/database/db-factory") as typeof import("../src/database/db-factory");
  dbFacGP.__resetDbFactoryForTesting();
  const expStGP = require("../src/services/experience-store") as typeof import("../src/services/experience-store");
  const seoRouterGP = (require("../src/routes/experiences-seo") as typeof import("../src/routes/experiences-seo")).default as any;

  const dbGP = dbFacGP.getDb("experiences");

  // Seed a fully-fleshed gårdssalg producer: adresse/lat/lon/epost/telefon all
  // set (so every practical-info row + the map block + JSON-LD geo/telephone/
  // email all get exercised), plus producer_type (set directly via SQL, same
  // as the gardssalg-book block above — no service-layer setter for this
  // column, it's populated by the enrichment pipeline in production).
  const provIdGP = expStGP.createProvider({
    navn: "Fjellro Sideri", org_nr: "912345679",
    fylke: "Innlandet", kommune: "Lillehammer", poststed: "Lillehammer",
    adresse: "Sideriveien 4", lat: 61.115, lon: 10.469,
    telefon: "61234567", epost: "post@fjellrosideri.no",
    brreg_verified: 0, verification_status: "pending_verify",
  });
  dbGP.prepare("UPDATE experience_providers SET producer_type = ? WHERE id = ?").run("sideri", provIdGP);
  expStGP.backfillProviderSlugs();

  // A second, bare-minimum producer — no fylke/kommune/poststed either (so
  // drivingSted() is empty and `facts` stays fully empty, not just missing
  // adresse/nettside/telefon/epost) — exercises the true "honest omission"
  // path: practical-info table absent entirely, map falls back to "posisjon
  // ikke registrert", about/visit copy falls back to the type-general
  // placeholder.
  const bareProvIdGP = expStGP.createProvider({
    navn: "Bekkely Bryggeri",
  });
  dbGP.prepare("UPDATE experience_providers SET producer_type = ? WHERE id = ?").run("bryggeri", bareProvIdGP);
  expStGP.backfillProviderSlugs();

  // invokeGP — same shape as the invokeGB helper in the gardssalg-book block:
  // find the router layer by path+method, drive its handler with a sync mock
  // req/res, skip any parsing middleware (GET-only here, no body needed).
  function invokeGP(
    routePath: string,
    params: Record<string, string>,
    reqPath: string
  ): { status: number; body: string; headers: Record<string, string> } {
    const layer = (seoRouterGP.stack as any[]).find(
      (l: any) => l.route && l.route.path === routePath && l.route.methods?.get
    );
    assertTrue(!!layer, `gp-route: router has GET ${routePath} layer`);
    if (!layer) return { status: 0, body: "", headers: {} };
    let status = 200; let body = ""; let nexted = false;
    const headers: Record<string, string> = {};
    const res: any = {
      statusCode: 200,
      setHeader: (k: string, v: string) => { headers[k.toLowerCase()] = String(v); },
      status: (c: number) => { status = c; res.statusCode = c; return res; },
      send: (b: unknown) => { body = typeof b === "string" ? b : String(b); return res; },
      json: (o: unknown) => { body = JSON.stringify(o); return res; },
    };
    const req: any = { path: reqPath, hostname: "opplevagent.no", params, query: {}, body: {} };
    const stack = (layer.route.stack as any[]).filter((s: any) => s.method === "get");
    const handle = stack[stack.length - 1].handle;
    handle(req, res, () => { nexted = true; });
    if (nexted) status = 404;
    return { status, body, headers };
  }

  // gp-01: unknown slug → 404 (next()) — same gate as the booking panel, so
  // an unresolvable slug never renders a profile either.
  const missGP = invokeGP("/kategori/gardssalg/produsent/:providerSlug",
    { providerSlug: "finnes-ikke" }, "/kategori/gardssalg/produsent/finnes-ikke");
  assertEq(missGP.status, 404, "gp-01: unknown provider slug → 404 (next())");

  const seededGP = expStGP.listGardssalgProviders(20, 0).find((p: any) => p.id === provIdGP);
  assertTrue(!!seededGP && !!seededGP.slug, "gp-02: seeded provider got a slug from backfillProviderSlugs()");
  const slugGP = String(seededGP!.slug);

  // gp-03: profile page renders for the fully-seeded producer — 200, all
  // sections present.
  const profGP = invokeGP("/kategori/gardssalg/produsent/:providerSlug",
    { providerSlug: slugGP }, `/kategori/gardssalg/produsent/${slugGP}`);
  assertEq(profGP.status, 200, "gp-03a: GET /kategori/gardssalg/produsent/<slug> → 200");
  assertTrue(/text\/html/.test(profGP.headers["content-type"] || ""), "gp-03b: profile Content-Type text/html");
  assertTrue(profGP.body.includes("Fjellro Sideri"), "gp-03c: profile shows provider name (hero h1)");
  assertTrue(profGP.body.includes("Lillehammer"), "gp-03d: profile shows the driving-sted (poststed/kommune/fylke)");
  assertTrue(profGP.body.includes(">Om produsenten<"), "gp-03e: 'Om produsenten' section present");
  assertTrue(profGP.body.includes(">Besøket<"), "gp-03f: 'Besøket' section present");
  assertTrue(profGP.body.includes(">Praktisk info<") || profGP.body.includes("Praktisk info"), "gp-03g: 'Praktisk info' section present");

  // gp-04: drink-type badge (sideri → "Sider" label, same DRINK_TYPE_META
  // source of truth shared with the booking panel and category cards).
  assertTrue(profGP.body.includes("Sider"), "gp-04: drink-type badge shows 'Sider' for producer_type=sideri");

  // gp-05: CTA links to the existing booking route for the SAME slug — the
  // booking flow itself is untouched by this profile-page slice.
  assertTrue(profGP.body.includes(`href="/kategori/gardssalg/book/${slugGP}"`),
    "gp-05: 'Reserver besøk' CTA links to the unchanged /kategori/gardssalg/book/<slug> route");
  assertTrue(profGP.body.includes("Reserver besøk"), "gp-05b: CTA button text present");

  // gp-06: practical-info rows — only real data, all five seeded fields.
  assertTrue(/<th scope="row">Sted<\/th>/.test(profGP.body), "gp-06a: practical info has a Sted row");
  assertTrue(profGP.body.includes("Sideriveien 4"), "gp-06b: practical info shows the seeded adresse");
  assertTrue(profGP.body.includes('href="tel:61234567"'), "gp-06c: practical info shows a tel: link for telefon");
  assertTrue(profGP.body.includes('href="mailto:post@fjellrosideri.no"'), "gp-06d: practical info shows a mailto: link for epost");

  // gp-07: map block — lat/lon present → an OpenStreetMap link, not the
  // "not registered" fallback.
  assertTrue(profGP.body.includes("openstreetmap.org/?mlat=61.115&mlon=10.469"),
    "gp-07a: map block links to OpenStreetMap with the seeded lat/lon");
  assertTrue(!profGP.body.includes("Nøyaktig posisjon er ikke registrert ennå"),
    "gp-07b: map block does NOT show the 'not registered' fallback when lat/lon exist");

  // gp-08: JSON-LD — LocalBusiness with address/geo/telephone/email, plus a
  // BreadcrumbList Forsiden → Gårdssalg og smaking → provider name.
  const ldMatchesGP = profGP.body.match(/<script type="application\/ld\+json">([^<]+)<\/script>/g) || [];
  assertEq(ldMatchesGP.length, 2, "gp-08a: exactly two JSON-LD scripts (LocalBusiness + BreadcrumbList)");
  const ldObjsGP = ldMatchesGP.map((s: string) => JSON.parse(s.replace(/^<script[^>]*>/, "").replace(/<\/script>$/, "")));
  const localBizGP = ldObjsGP.find((o: any) => o["@type"] === "LocalBusiness");
  assertTrue(!!localBizGP, "gp-08b: a LocalBusiness JSON-LD block is present");
  assertEq(localBizGP?.name, "Fjellro Sideri", "gp-08c: LocalBusiness name matches the provider");
  assertEq(localBizGP?.address?.streetAddress, "Sideriveien 4", "gp-08d: LocalBusiness address.streetAddress matches");
  assertEq(localBizGP?.geo?.latitude, 61.115, "gp-08e: LocalBusiness geo.latitude matches the seeded lat");
  assertEq(localBizGP?.telephone, "61234567", "gp-08f: LocalBusiness telephone matches");
  assertEq(localBizGP?.email, "post@fjellrosideri.no", "gp-08g: LocalBusiness email matches");
  assertEq(localBizGP?.offers?.url, `https://opplevagent.no/kategori/gardssalg/book/${slugGP}`,
    "gp-08h: LocalBusiness offers.url points at the booking route (absolute URL)");
  const breadcrumbGP = ldObjsGP.find((o: any) => o["@type"] === "BreadcrumbList");
  assertTrue(!!breadcrumbGP, "gp-08i: a BreadcrumbList JSON-LD block is present");
  assertEq(breadcrumbGP?.itemListElement?.length, 3, "gp-08j: breadcrumb has 3 items (Forsiden / Gårdssalg og smaking / provider)");
  assertEq(breadcrumbGP?.itemListElement?.[2]?.name, "Fjellro Sideri", "gp-08k: last breadcrumb item is the provider name");

  // gp-09: Open Graph + Twitter tags.
  assertTrue(profGP.body.includes('property="og:title" content="Fjellro Sideri | Opplevagent"'),
    "gp-09a: og:title includes the provider name");
  assertTrue(profGP.body.includes('property="og:type" content="website"'), "gp-09b: og:type present");
  assertTrue(profGP.body.includes(`property="og:url" content="https://opplevagent.no/kategori/gardssalg/produsent/${slugGP}"`),
    "gp-09c: og:url is the canonical profile URL");
  assertTrue(profGP.body.includes('name="twitter:card" content="summary"'), "gp-09d: twitter:card present");

  // gp-10: bare-minimum producer (no adresse/lat/lon/epost/telefon/hjemmeside)
  // still renders 200, with the honest-omission fallbacks — no fabricated
  // practical info, no fake map position.
  const bareRowGP = expStGP.listGardssalgProviders(20, 0).find((p: any) => p.id === bareProvIdGP);
  assertTrue(!!bareRowGP && !!bareRowGP.slug, "gp-10a: bare producer also got a slug");
  const bareSlugGP = String(bareRowGP!.slug);
  const bareProfGP = invokeGP("/kategori/gardssalg/produsent/:providerSlug",
    { providerSlug: bareSlugGP }, `/kategori/gardssalg/produsent/${bareSlugGP}`);
  assertEq(bareProfGP.status, 200, "gp-10b: bare producer profile still renders 200");
  assertTrue(bareProfGP.body.includes("Praktisk info legges til etter hvert som profilen berikes"),
    "gp-10c: bare producer shows the honest 'not yet enriched' practical-info fallback (no fabricated rows)");
  assertTrue(bareProfGP.body.includes("Nøyaktig posisjon er ikke registrert ennå"),
    "gp-10d: bare producer shows the honest 'position not registered' map fallback");

  // gp-11: /kategori/gardssalg category-card name-link now points at the new
  // profile route (not straight at the booking panel) — the "Book besøk"
  // button stays a direct shortcut to booking, unaffected.
  const listGP = invokeGP("/kategori/gardssalg", {}, "/kategori/gardssalg");
  assertEq(listGP.status, 200, "gp-11a: GET /kategori/gardssalg → 200");
  assertTrue(listGP.body.includes(`href="/kategori/gardssalg/produsent/${slugGP}"`),
    "gp-11b: category listing links the provider name to the new profile route");
  assertTrue(listGP.body.includes(`href="/kategori/gardssalg/book/${slugGP}"`),
    "gp-11c: category listing's 'Book besøk' CTA still links straight to the booking route");

  // gp-12: no-regression check — the booking panel route (unchanged by this
  // slice) still renders 200 for the same slug the profile page now serves.
  const bookLayerPresentGP = (seoRouterGP.stack as any[]).some(
    (l: any) => l.route && l.route.path === "/kategori/gardssalg/book/:providerSlug" && l.route.methods?.get
  );
  assertTrue(bookLayerPresentGP, "gp-12a: booking panel GET route is still registered on the router");
  if (bookLayerPresentGP) {
    const bookLayerGP = (seoRouterGP.stack as any[]).find(
      (l: any) => l.route && l.route.path === "/kategori/gardssalg/book/:providerSlug" && l.route.methods?.get
    );
    let bookStatusGP = 200; let bookBodyGP = ""; let bookNextedGP = false;
    const bookResGP: any = {
      statusCode: 200,
      setHeader: () => {},
      status: (c: number) => { bookStatusGP = c; bookResGP.statusCode = c; return bookResGP; },
      send: (b: unknown) => { bookBodyGP = typeof b === "string" ? b : String(b); return bookResGP; },
      json: (o: unknown) => { bookBodyGP = JSON.stringify(o); return bookResGP; },
    };
    const bookReqGP: any = { path: `/kategori/gardssalg/book/${slugGP}`, hostname: "opplevagent.no", params: { providerSlug: slugGP }, query: {}, body: {} };
    const bookStackGP = (bookLayerGP.route.stack as any[]).filter((s: any) => s.method === "get");
    bookStackGP[bookStackGP.length - 1].handle(bookReqGP, bookResGP, () => { bookNextedGP = true; });
    if (bookNextedGP) bookStatusGP = 404;
    assertEq(bookStatusGP, 200, "gp-12b: booking panel still renders 200 for the same provider slug (no regression)");
    assertTrue(bookBodyGP.includes("Fjellro Sideri"), "gp-12c: booking panel still shows the provider name (no regression)");
  }

  if (prevPathGP === undefined) delete process.env.EXPERIENCES_DB_PATH;
  else process.env.EXPERIENCES_DB_PATH = prevPathGP;
  dbFacGP.__resetDbFactoryForTesting();
  console.log("  gardssalg-profile: OK (unknown-slug 404, full profile render + sections, badge, CTA, practical-info, map, JSON-LD, OG/Twitter, category-card link, booking-panel regression)");
})();

// ─── gardssalg-content-enrichment: pure extractors (2026-07-10, Fase 1 item 3
//     of the rike-profiler dev-request) ────────────────────────────────────
// Unit coverage for the multi-page-crawl slice's two new pure extractors:
// summarizeVisit (same shape as summarizeAbout, but keyword-scans for
// visit/tasting signal) and extractOpeningHours (scans already-extracted
// visible text for a weekday+time or åpningstider/åpent+time snippet). Both
// are PURE — no network, no DB — so this block is a plain synchronous IIFE,
// same convention as every other pure-function unit test in this file.
console.log("\n── gardssalg-content-enrichment: summarizeVisit / extractOpeningHours (pure) ──");
(() => {
  const { summarizeVisit, extractOpeningHours, extractVisibleText } =
    require("../src/services/search-enrich") as typeof import("../src/services/search-enrich");

  // ── summarizeVisit ──────────────────────────────────────────────────────
  {
    const html = "<html><body><p>Velkommen til gården vår.</p><p>Vi tilbyr omvisning i bryggeriet og en smaking av våre øl hver lørdag.</p></body></html>";
    const sum = summarizeVisit(html);
    assertTrue(sum.includes("omvisning") && sum.includes("smaking"), "summarizeVisit: finds a sentence mentioning omvisning/smaking keywords");
  }
  {
    const html = "<html><body><p>Vi har åpent gårdsutsalg hver dag fra ti til fire, kom gjerne innom for å handle direkte fra oss på gården.</p></body></html>";
    const sum = summarizeVisit(html);
    assertTrue(sum.toLowerCase().includes("åpent gårdsutsalg"), "summarizeVisit: finds the 'åpent gårdsutsalg' keyword");
  }
  {
    const html = "<html><body><p>Dette er en helt vanlig setning om gårdens historie og ingenting annet som er relevant her i det hele tatt.</p></body></html>";
    assertEq(summarizeVisit(html), "", "summarizeVisit: no visit/tasting keyword anywhere → empty string (no leading-slice fallback)");
  }
  assertEq(summarizeVisit(""), "", "summarizeVisit: empty html → empty string");
  {
    const longSentence =
      "Et flott sted for smaking av lokale produkter fra egen gård og hage, " +
      "med mye å se og oppleve for hele familien, ".repeat(15) +
      "velkommen innom.";
    const sum = summarizeVisit(`<html><body><p>${longSentence}</p></body></html>`);
    assertTrue(sum.length > 0 && sum.length <= 300, "summarizeVisit: caps a long matching sentence at ~300 chars");
  }

  // ── extractOpeningHours ─────────────────────────────────────────────────
  {
    const text = extractVisibleText("<p>Åpningstider: Mandag-fredag 10:00-16:00, lørdag stengt.</p>");
    const hours = extractOpeningHours(text);
    assertTrue(!!hours && /10:00/.test(hours) && /mandag/i.test(hours), "extractOpeningHours: weekday name + HH:MM time pattern → snippet");
  }
  {
    const text = "Vi har åpent man-fre 9-17, velkommen innom.";
    const hours = extractOpeningHours(text);
    assertTrue(!!hours && /man-fre/i.test(hours), "extractOpeningHours: 'man-fre' abbreviation range co-located with a time pattern");
  }
  {
    const text = "Åpningstider 10-18 alle hverdager, se nettsiden for detaljer.";
    const hours = extractOpeningHours(text);
    assertTrue(!!hours && /10-18/.test(hours), "extractOpeningHours: 'åpningstider' + time pattern, no weekday name needed");
  }
  {
    const text = "Vi åpnet gården vår i 1998 og har drevet siden.";
    assertEq(extractOpeningHours(text), null, "extractOpeningHours: 'åpnet' (different word, past tense) alone → null");
  }
  assertEq(extractOpeningHours(""), null, "extractOpeningHours: empty text → null");
  {
    const text = "This bakery is open Monday to Friday from 9am, come visit us anytime.";
    assertEq(extractOpeningHours(text), null, "extractOpeningHours: English weekday names don't match the Norwegian pattern → null");
  }
  {
    const hours = extractOpeningHours("Mandag er vår favorittdag i uken, ingenting mer å si her.");
    assertEq(hours, null, "extractOpeningHours: weekday name with no nearby time or åpningstider/åpent keyword → null");
  }

  console.log("  gardssalg-content-enrichment (pure): OK (summarizeVisit + extractOpeningHours unit tests)");
})();

// ─── gardssalg-content-refresh: POST /api/opplevelser/admin/gardssalg-content-
//     refresh (2026-07-10, Fase 1 item 3 of the rike-profiler dev-request) ──
// Drives the REAL opplevelser router over HTTP against an in-memory
// experiences.db, same real-HTTP-server pattern as orch-pr-18 (bulk-load) /
// orch-pr-dedup-backfill-endpoint above (this block explicitly serializes
// AFTER that one, since both mutate the shared experiences db-factory
// singleton). Since this route makes real fetch() calls to a producer's
// hjemmeside, and the CI/sandbox has no network access to arbitrary URLs,
// this suite deliberately exercises only the paths that don't require a
// successful fetch: the admin auth-gate, the LOCK check (which this route
// short-circuits on BEFORE any fetch — see the route's doc comment), and the
// apply/dry-run attempt-stamping + providerIds-override plumbing. A seeded
// unlocked provider's hjemmeside is a URL isSafeFetchUrl() rejects outright
// (http://localhost/), so its fetch fails FAST (no real network wait,
// no 10s timeout) and lands in `errors` — enough to verify the plumbing
// without a live network round-trip. The pure extraction logic itself
// (summarizeVisit/extractOpeningHours/summarizeAbout/meetsAboutQualityBar)
// is covered independently by the pure-function block above.
console.log("\n── gardssalg-content-refresh: POST /api/opplevelser/admin/gardssalg-content-refresh ──");

let _gardssalgContentRefreshResolve: () => void = () => {};
const _gardssalgContentRefreshPromise: Promise<void> = new Promise<void>((r) => {
  _gardssalgContentRefreshResolve = r;
});

(async () => {
  // Serialize after the prior DB-mutating async block (also swaps the
  // experiences db-factory singleton) — same reasoning as that block's own
  // "Run after the prior DB-mutating IIFE" comment.
  try { await _orchPrDedupBackfillEndpointPromise; } catch { /* upstream */ }

  const prevPathGCR = process.env.EXPERIENCES_DB_PATH;
  const prevAdminKeyGCR = process.env.ADMIN_KEY;
  let serverGCR: import("http").Server | null = null;
  try {
    process.env.EXPERIENCES_DB_PATH = ":memory:";

    const dbFactoryPathGCR = require.resolve("../src/database/db-factory");
    const expStorePathGCR = require.resolve("../src/services/experience-store");
    const opplevelserPathGCR = require.resolve("../src/routes/opplevelser");
    delete require.cache[dbFactoryPathGCR];
    delete require.cache[expStorePathGCR];
    delete require.cache[opplevelserPathGCR];

    const dbFactoryGCR = require("../src/database/db-factory") as typeof import("../src/database/db-factory");
    dbFactoryGCR.__resetDbFactoryForTesting();
    const expStoreGCR = require("../src/services/experience-store") as typeof import("../src/services/experience-store");
    const opplevelserGCR = require("../src/routes/opplevelser") as { default: import("express").Router };

    const dbGCR = dbFactoryGCR.getDb("experiences");

    // ── Seed A: a LOCKED gårdssalg provider (content_source='manual') — its
    // hjemmeside is a normal-looking URL that would (if this route ever
    // reached the fetch stage for it) attempt a real network call, but the
    // lock check must short-circuit BEFORE that ever happens.
    const lockedIdGCR = expStoreGCR.createProvider({
      navn: "Låst Bryggeri", org_nr: "911000111",
      fylke: "Vestland", kommune: "Voss",
      hjemmeside: "https://locked-brewery.example.no",
    });
    dbGCR.prepare("UPDATE experience_providers SET producer_type = ?, content_source = ? WHERE id = ?")
      .run("bryggeri", "manual", lockedIdGCR);

    // ── Seed B: an UNLOCKED gårdssalg provider whose hjemmeside is a URL
    // isSafeFetchUrl() rejects outright (localhost) — its fetch fails FAST
    // (no real network, no timeout wait), landing in `errors`.
    const unlockedIdGCR = expStoreGCR.createProvider({
      navn: "Ustabil Sideri", org_nr: "911000222",
      fylke: "Vestland", kommune: "Voss",
      hjemmeside: "http://localhost/",
    });
    dbGCR.prepare("UPDATE experience_providers SET producer_type = ? WHERE id = ?")
      .run("sideri", unlockedIdGCR);

    // ── Mount the REAL router on a minimal Express app. ────────────────
    const expressModGCR = (await import("express")).default;
    const appGCR = expressModGCR();
    appGCR.use(expressModGCR.json());

    const httpModGCR = await import("http");
    serverGCR = httpModGCR.createServer(appGCR);
    await new Promise<void>((resolve) => serverGCR!.listen(0, "127.0.0.1", () => resolve()));
    const addrGCR = serverGCR.address();
    const portGCR = typeof addrGCR === "object" && addrGCR ? addrGCR.port : 0;

    const ADMIN_KEY_GCR = "gardssalg-content-refresh-test-admin-key";
    process.env.ADMIN_KEY = ADMIN_KEY_GCR;
    appGCR.use("/api/opplevelser/admin", (_req, _res, next) => {
      process.env.ADMIN_KEY = ADMIN_KEY_GCR;
      next();
    });
    appGCR.use("/api/opplevelser", opplevelserGCR.default);

    function gcrReq(body: Record<string, unknown>, key?: string): Promise<{ status: number; body: any }> {
      const payload = JSON.stringify(body);
      const headers: Record<string, string> = {
        "content-type": "application/json",
        "content-length": String(Buffer.byteLength(payload)),
      };
      if (key !== undefined) headers["x-admin-key"] = key;
      return new Promise((resolve, reject) => {
        const r = httpModGCR.request(
          {
            method: "POST", host: "127.0.0.1", port: portGCR,
            path: "/api/opplevelser/admin/gardssalg-content-refresh",
            headers,
          },
          (resp) => {
            const chunks: Buffer[] = [];
            resp.on("data", (c) => chunks.push(c as Buffer));
            resp.on("end", () => {
              const raw = Buffer.concat(chunks).toString("utf8");
              let parsed: any = null;
              try { parsed = raw ? JSON.parse(raw) : null; } catch { parsed = { _raw: raw }; }
              resolve({ status: resp.statusCode || 0, body: parsed });
            });
          }
        );
        r.on("error", reject);
        r.write(payload);
        r.end();
      });
    }

    const attemptAtOf = (id: string): string | null =>
      (dbGCR.prepare("SELECT last_content_attempt_at FROM experience_providers WHERE id = ?").get(id) as
        | { last_content_attempt_at: string | null }
        | undefined)?.last_content_attempt_at ?? null;

    // ── gcr-1/2: admin gate. ─────────────────────────────────────────
    {
      const r = await gcrReq({ providerIds: [lockedIdGCR], apply: true });
      assertEq(r.status, 403, "gcr-1: missing X-Admin-Key → 403");
    }
    {
      const r = await gcrReq({ providerIds: [lockedIdGCR], apply: true }, "wrong-key");
      assertEq(r.status, 403, "gcr-2: wrong X-Admin-Key → 403");
    }
    assertEq(attemptAtOf(lockedIdGCR), null, "gcr-2b: pre-call, locked provider has no attempt timestamp yet");

    // ── gcr-3: apply=1 on the LOCKED provider (via providerIds override) →
    // skipped_locked, no fetch, no error, response shape sane. ──────────
    {
      const r = await gcrReq({ providerIds: [lockedIdGCR], apply: true }, ADMIN_KEY_GCR);
      assertEq(r.status, 200, "gcr-3a: correct X-Admin-Key + apply → 200");
      assertEq(r.body.dry_run, false, "gcr-3b: dry_run: false when apply=true");
      assertEq(r.body.scanned, 0, "gcr-3c: scanned: 0 — locked provider never reaches the fetch stage");
      assertTrue(Array.isArray(r.body.skipped_locked) && r.body.skipped_locked.includes(lockedIdGCR),
        "gcr-3d: skipped_locked includes the locked provider's id");
      assertEq(r.body.changed.length, 0, "gcr-3e: changed: [] — nothing written for a locked provider");
      assertEq(r.body.errors.length, 0, "gcr-3f: errors: [] — the lock check short-circuits before any fetch, so no fetch error either");
      assertTrue(
        typeof r.body.by_field === "object" &&
        "about_text" in r.body.by_field && "visit_text" in r.body.by_field && "opening_hours_text" in r.body.by_field,
        "gcr-3g: by_field carries the three gårdssalg content keys"
      );
    }

    // ── gcr-4: apply mode stamps last_content_attempt_at UNCONDITIONALLY,
    // even for a locked provider (same "cycle to the back of the queue on any
    // outcome" discipline as the experiences-table route). ──────────────
    const stampedAtGCR = attemptAtOf(lockedIdGCR);
    assertTrue(!!stampedAtGCR, "gcr-4: locked provider's last_content_attempt_at is now set after an apply-mode call");

    // ── gcr-5: dry-run (apply omitted) must NOT re-stamp the attempt. ────
    {
      const r = await gcrReq({ providerIds: [lockedIdGCR] }, ADMIN_KEY_GCR);
      assertEq(r.status, 200, "gcr-5a: dry-run call → 200");
      assertEq(r.body.dry_run, true, "gcr-5b: dry_run: true when apply is omitted");
      assertTrue(Array.isArray(r.body.skipped_locked) && r.body.skipped_locked.includes(lockedIdGCR),
        "gcr-5c: dry-run still reports the locked provider as skipped_locked");
    }
    assertEq(attemptAtOf(lockedIdGCR), stampedAtGCR, "gcr-5d: dry-run does NOT change last_content_attempt_at (stays at its apply-mode value)");

    // ── gcr-6/7: apply=1 on the UNLOCKED provider whose hjemmeside is
    // rejected by isSafeFetchUrl (localhost) — fetch fails fast, lands in
    // errors, is NOT counted as scanned, and still gets its attempt stamped.
    assertEq(attemptAtOf(unlockedIdGCR), null, "gcr-6a: pre-call, unlocked provider has no attempt timestamp yet");
    {
      const r = await gcrReq({ providerIds: [unlockedIdGCR], apply: true }, ADMIN_KEY_GCR);
      assertEq(r.status, 200, "gcr-6b: apply call on the unlocked provider → 200");
      assertEq(r.body.scanned, 0, "gcr-6c: scanned: 0 — the fetch never succeeds");
      assertEq(r.body.skipped_locked.length, 0, "gcr-6d: skipped_locked: [] — this provider is NOT locked");
      assertEq(r.body.changed.length, 0, "gcr-6e: changed: [] — nothing to write without a successful fetch");
      assertTrue(Array.isArray(r.body.errors) && r.body.errors.length === 1 && r.body.errors[0].provider_id === unlockedIdGCR,
        "gcr-6f: errors carries exactly one entry for the unreachable-by-design hjemmeside");
    }
    assertTrue(!!attemptAtOf(unlockedIdGCR), "gcr-7: unlocked provider's last_content_attempt_at is also stamped in apply mode (unconditional, before the fetch)");

    // ── gcr-8: providerIds override with an unknown id → resolves to no
    // targets (getGardssalgProviderContentTarget returns null), NOT a crash —
    // an empty, well-shaped 200 response. ───────────────────────────────
    {
      const r = await gcrReq({ providerIds: ["does-not-exist"], apply: true }, ADMIN_KEY_GCR);
      assertEq(r.status, 200, "gcr-8a: unknown providerId → 200 (no crash)");
      assertEq(r.body.scanned, 0, "gcr-8b: scanned: 0");
      assertEq(r.body.changed.length, 0, "gcr-8c: changed: []");
      assertEq(r.body.errors.length, 0, "gcr-8d: errors: [] — an unresolvable id is silently filtered out of targets, not treated as a fetch error");
    }

    // ── gcr-9: auto-select (no providerIds) excludes the LOCKED provider —
    // only the unlocked one is eligible, so it (not the locked one) is the
    // one that ends up in errors after its (fast, local) fetch fails. ───
    {
      const r = await gcrReq({ apply: true, limit: 10 }, ADMIN_KEY_GCR);
      assertEq(r.status, 200, "gcr-9a: auto-select apply call → 200");
      assertTrue(!r.body.skipped_locked.includes(lockedIdGCR), "gcr-9b: auto-select never even selects the locked provider (excluded by the WHERE clause, not filtered post-hoc)");
      assertTrue(r.body.errors.some((e: any) => e.provider_id === unlockedIdGCR),
        "gcr-9c: auto-select picks up the unlocked provider, whose fetch still fails fast");
    }

    dbFactoryGCR.__resetDbFactoryForTesting();
  } catch (err) {
    failed++;
    failures.push("gardssalg-content-refresh: unexpected error: " + String(err));
  } finally {
    if (serverGCR) {
      await new Promise<void>((resolve) => serverGCR!.close(() => resolve()));
    }
    if (prevPathGCR === undefined) delete process.env.EXPERIENCES_DB_PATH;
    else process.env.EXPERIENCES_DB_PATH = prevPathGCR;
    if (prevAdminKeyGCR === undefined) delete process.env.ADMIN_KEY;
    else process.env.ADMIN_KEY = prevAdminKeyGCR;
    console.log("  gardssalg-content-refresh: OK (auth-gate, lock-check-before-fetch, apply-vs-dry-run attempt stamping, providerIds override, auto-select exclusion)");
    _gardssalgContentRefreshResolve();
  }
})();

// ── orch-pr-20260704 tasks-prune-async: background job for /ops/tasks-prune
// and /ops/vacuum, so the 2026-07-04 incident (a single-transaction DELETE
// over ~4093 `tasks` rows, immediately followed by wal_checkpoint(TRUNCATE),
// blocked the single-threaded Node event loop for ~12 minutes) can't recur.
// This block uses its own in-memory DB + own express app/HTTP server on an
// ephemeral port, but — like many other blocks in this file — it DOES pin
// the shared getDb() singleton (via __setDbForTesting) for the duration of
// its HTTP requests, and it shares process.env.ANALYTICS_ADMIN_KEY with
// every other block that exercises analytics.ts admin routes.
//
// 2026-07-05 CI fix (3rd attempt — see git history for the two superseded
// ones): this block used to be a bare fire-and-forget top-level IIFE, NOT
// part of the file's _prNN-style handle-coordination scheme at all, relying
// on finishing "well before process.exit" because the REPORT IIFE's own
// chain of awaits takes many seconds. That margin is not guaranteed on every
// runner, and CI reproduced it: this block's real-I/O req() loop (HTTP round
// trips, setTimeout/setImmediate polling) re-pins the shared getDb()
// singleton at unpredictable wall-clock moments, and — being a plain
// top-level fire-and-forget IIFE — it can race EVERY OTHER singleton-pinning
// block in the file, not just agent-knowledge-get-auth.
//
// Attempt 1 (agent-knowledge-get-auth.test.ts re-pinning the db immediately
// before each of its own router.handle() calls) failed identically on CI
// because it only defends the instant of THAT suite's own db read; it does
// nothing to stop this block from mutating the shared singleton at any other
// moment, including during any OTHER suite's db access.
//
// Attempt 2 (this comment, superseded within this same PR iteration) chained
// this block off _agentKnowledgeGetAuthPromise alone, on the theory that
// putting it "after the last _prNN link" was enough. That is insufficient:
// this file does NOT have one single linear chain — it has several
// independently-resolving branches of _prNN-style handles that only get
// jointly awaited at the very end (in the REPORT IIFE's tail, "to avoid
// exiting early" per the _homepageProvenanceEmailBackfillPromise comment
// above), without being ordered against each other during execution.
// _agentKnowledgeGetAuthPromise's own ancestry (_homepageProvenanceEmailBackfillPromise
// → Promise.all([_contactClickTrackingPromise, _orchPr20260614Promise]) → ...)
// is only ONE such branch; chaining off it alone left this block free to
// start while OTHER branches (e.g. _orchPr20260614_5Promise's cat-* catalog
// suite) were still in flight — reproduced locally: this block's own
// __setDbForTesting(tpaDb) call landed mid-suite there and crashed a
// products-array assertion with a plain undefined-length TypeError.
//
// The only fix that removes the race categorically (not just narrows the
// odds, and not just against one branch) is to make this block depend on
// EVERY branch the REPORT IIFE itself awaits — i.e. the exact same
// dependency set, collected below in the same order — via Promise.allSettled
// (not Promise.all/.then, so that even if some upstream link were to reject
// this block still runs rather than silently vanishing). Once every one of
// those has settled, there is no remaining code path anywhere in the file
// that can still be executing a __setDbForTesting call (or building a
// response that depends on one), so this block's own db-singleton mutations
// are provably the last ones in the process, full stop. The req() helper
// below keeps its defensive re-pin/retry as harmless extra defense-in-depth,
// but it is no longer what makes this block safe.
let _tasksPruneAsyncResolve: () => void = () => {};
const _tasksPruneAsyncPromise: Promise<void> = new Promise<void>(r => {
  _tasksPruneAsyncResolve = r;
});

// Same dependency set as the REPORT IIFE's own tail-await list below (every
// entry from _serialChain through _oaHomeCountersPromise, i.e. everything
// EXCEPT _tasksPruneAsyncPromise itself) — kept literally identical on
// purpose so "does this block depend on everything the REPORT IIFE depends
// on" is true by inspection, not by re-derivation. 2026-07-06 merge note:
// _oaHomeCountersPromise (orch-pr-oa-counter-strip) was added here, not just
// appended to the tail-await list, for the same db-singleton-swap reason
// as every other entry above — see its own chaining comment for why it now
