    const sitemapHandler = sitemapLayerPBH.route.stack[sitemapLayerPBH.route.stack.length - 1].handle;
    sitemapHandler({ path: "/sitemap.xml", hostname: "opplevagent.no", params: {}, query: {} } as any, sitemapRes, () => {});

